t(key) // 如果 dep 不存在，则生成一个新的 dep，并放入到 depsMap 中 if (!dep) { depsMap.set(key, (dep = new Set())) } // 把所有的 activeEffect 方法加入到 dep 中 dep.add(activeEffect) }</li></ul><p>/**</p><ul><li>触发依赖 */ function trigger(target, key) { // 依据 target 获取存储的 map 实例 const depsMap = targetMap.get(target) // 如果 map 不存在，则直接 return if (!depsMap) { return } // 依据指定的 key，获取 dep 实例 let dep = depsMap.get(key) // dep 不存在则直接 return if (!dep) { return } // 触发 dep triggerEffects(dep) }</li></ul><p>/**</p><ul><li>依次触发 dep 中保存的依赖 */ function triggerEffects(dep) { // 把 dep 构建为一个数组 const effects = Array.isArray(dep) ? dep : [...dep] // 依次触发 for (const effect of effects) { effect.run() } }</li></ul><p>/**</p><ul><li>proxy 的 handler */ const baseHandlers = { get: (target, key, receiver) =&gt; { // 利用 Reflect 得到返回值 const res = Reflect.get(target, key, receiver) // 收集依赖 track(target, key) return res }, set: (target, key, value, receiver) =&gt; { // 利用 Reflect.set 设置新值 const result = Reflect.set(target, key, value, receiver) // 触发依赖 trigger(target, key) return result } }</li></ul><p>function reactive(target) { const proxy = new Proxy(target, baseHandlers) return proxy }</p><p>// --------------- ref 模块 --------------- class RefImpl { _rawValue _value dep</p><pre><code> constructor(value) {
